import React, { useState } from 'react';

function Contact() {
  const [form, setForm] = useState({ name: '', email: '', checkin: '', checkout: '', message: '' });
  const [sent, setSent] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    setSent(true);
    setForm({ name: '', email: '', checkin: '', checkout: '', message: '' });
    setTimeout(() => setSent(false), 4000);
  };

  return (
    <section id="contact">
      <div className="section">
        <p className="section-tag">Contact Us</p>
        <h2>Begin Your Journey</h2>
        <p className="sub">Our team is ready to craft your perfect escape. Reach out anytime.</p>

        <div className="contact-grid">
          {/* Info */}
          <div className="contact-info">
            <p><strong>📍 Address</strong><br />North Malé Atoll, Maldives</p>
            <p><strong>📞 Phone</strong><br />+960 123 456 789</p>
            <p><strong>✉️ Email</strong><br />reservations@sunsetresort.com</p>
            <p><strong>🕐 Check-in / Check-out</strong><br />2:00 PM / 11:00 AM</p>

            {/* Google Map */}
            <div className="contact-map">
              <iframe
                title="Resort Location"
                src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d126743.56!2d73.384988!3d4.174994!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3b3ff3f20ee39f8f%3A0x4c!2sMaldives!5e0!3m2!1sen!2s!4v1700000000"
                width="100%"
                height="220"
                style={{ border: 0, display: 'block' }}
                allowFullScreen=""
                loading="lazy"
              />
            </div>
          </div>

          {/* Form */}
          {/* <form className="contact-form" onSubmit={handleSubmit}>
            <h3>Make a Reservation</h3>
            {sent && <p className="success-msg">✓ Sent! We'll reply within 2 hours.</p>}

            <div className="form-row">
              <input placeholder="Full Name" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required />
              <input type="email" placeholder="Email Address" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required />
            </div>
            <div className="form-row">
              <input type="date" placeholder="Check-in" value={form.checkin} onChange={(e) => setForm({ ...form, checkin: e.target.value })} required />
              <input type="date" placeholder="Check-out" value={form.checkout} onChange={(e) => setForm({ ...form, checkout: e.target.value })} required />
            </div>
            <textarea placeholder="Special requests or message..." rows="4" value={form.message} onChange={(e) => setForm({ ...form, message: e.target.value })} />
            <button type="submit" className="submit-btn">Send Reservation Request</button>
          </form> */}
        </div>
      </div>
    </section>
  );
}

export default Contact;
